import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.servlet.mvc.support.RedirectAttributes;

@Controller
public class OAuthRedirectController {

    private static final String AUTH_SERVER_URL = "YOUR_AUTH_SERVER_URL";
    private static final String CLIENT_ID = "YOUR_CLIENT_ID";
    private static final String REDIRECT_URI = "YOUR_REDIRECT_URI";
    private static final String SCOPE = "YOUR_SCOPE";
    private static final String RESPONSE_TYPE = "code";

    @GetMapping("/oauth/authorize")
    public String redirectToAuthorizationServer(RedirectAttributes redirectAttributes) {
        String authorizationUrl = AUTH_SERVER_URL + "?client_id=" + CLIENT_ID +
                "&redirect_uri=" + REDIRECT_URI +
                "&scope=" + SCOPE +
                "&response_type=" + RESPONSE_TYPE;

        redirectAttributes.addAttribute("redirectUrl", authorizationUrl);

        return "redirect";
    }
}